import anthropic

client = anthropic.Anthropic()

# Static example library
EXAMPLES = [
    {
        "input": "Reset my password",
        "output": '{"intent":"account","action":"password_reset","needs_auth":true}'
    },
    {
        "input": "What's the weather in Oslo?",
        "output": '{"intent":"general","action":"none","needs_auth":false}'
    },
    {
        "input": "Show me my last 5 orders",
        "output": '{"intent":"commerce","action":"list_orders","needs_auth":true}'
    },
]

def build_few_shot_prompt(live_input: str) -> str:
    parts = []
    for ex in EXAMPLES:
        parts.append(f"<example>\n<input>{ex['input']}</input>\n<output>{ex['output']}</output>\n</example>")
    parts.append(f"<input>{live_input}</input>\n<output>")
    return "\n\n".join(parts)

def classify_intent(user_message: str) -> dict:
    prompt = build_few_shot_prompt(user_message)
    response = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=256,
        messages=[{"role": "user", "content": prompt}],
    )
    raw = response.content[0].text.strip().rstrip("</output>").strip()
    import json
    return json.loads(raw)

# Usage
result = classify_intent("Cancel order #8821 — I ordered by mistake")
print(result)
# {"intent": "commerce", "action": "cancel_order", "needs_auth": true}
